import { ActionPageSubmission } from '@domain/actionPages';
import { IErrorResponse } from '@domain/error';
import { PublicActionPage } from '@domain/publicActionPage';
import { PublicSubmission } from '@domain/submission';
import { ApiClient } from '@service/anedot/client';
import { useMutation } from 'react-query';

export type ActionPageSubmissionRequest = {
  submission: ActionPageSubmission;
  type: PublicActionPage['pageType'] | 'process_payment';
  useAuthCaptureOverride?: boolean;
};

export const useSubmitActionPage = (useAuthCapture = false) => {
  const mutation = useMutation<
    PublicSubmission,
    IErrorResponse,
    ActionPageSubmissionRequest,
    string
  >(({ submission, type, useAuthCaptureOverride }: ActionPageSubmissionRequest) => {
    const useAuthCaptureNormalized = useAuthCaptureOverride ?? useAuthCapture;
    const url =
      useAuthCaptureNormalized && type === 'donation'
        ? '/submissions/donation_auth'
        : `/submissions/${type}`;
    return new ApiClient({ namespace: 'public' }).post<ActionPageSubmission, PublicSubmission>(
      url,
      submission
    );
  });

  return {
    ...mutation,
    submitActionPage: mutation.mutate,
    submitActionPageAsync: mutation.mutateAsync,
  };
};

