import { ActionPageSubmission } from '@domain/actionPages';
import { InlineBillingAgreement } from '@domain/billingAgreement';
import { PublicSubmission, SubmissionPaymentMethods } from '@domain/submission';
import { useCallback } from 'react';
import { useProcessPayment } from './useProcessPayment';
import { ActionPageSubmissionRequest, useSubmitActionPage } from './useSubmitActionPage';
import { useSubmitEventPage } from './useSubmitEventPage';

type Options = {
  billingAgreements: InlineBillingAgreement[];
  ddcSessionId?: string;
  useAuthCapture?: boolean;
  useSubPaymentFlow?: boolean;
};

export const useActionPagePaymentSubmission = ({
  billingAgreements,
  ddcSessionId,
  useAuthCapture = false,
  useSubPaymentFlow = false,
}: Options) => {
  const {
    error: paymentError,
    isLoading: isProcessingPayment,
    processPayment,
  } = useProcessPayment({ billingAgreements, ddcSessionId });
  const {
    error: submissionError,
    isLoading: isSubmitting,
    submitActionPageAsync,
  } = useSubmitActionPage(useAuthCapture);

  const {
    error: eventSubmissionError,
    isLoading: isSubmittingEvent,
    submitEventPageAsync,
  } = useSubmitEventPage();

  const submit = useCallback(
    async (request: ActionPageSubmissionRequest): Promise<PublicSubmission> => {
      const isEventPage =
        request.submission.eventTicketsAttributes &&
        request.submission.eventTicketsAttributes.length > 0;

      if (
        useSubPaymentFlow &&
        (request.submission.submissionPaymentMethodAttributes?.type ===
          SubmissionPaymentMethods.CreditCard ||
          request.submission.submissionPaymentMethodAttributes?.type ===
            SubmissionPaymentMethods.BankAccount ||
          request.submission.submissionPaymentMethodAttributes?.type ===
            SubmissionPaymentMethods.Saved)
      ) {
        const { paymentIntent, paymentMethod } = await processPayment(request);

        const submissionPaymentMethodAttributes: ActionPageSubmission['submissionPaymentMethodAttributes'] =
          {
            customerCoveredFees:
              request.submission.submissionPaymentMethodAttributes?.customerCoveredFees,
            paymentMethodId: paymentMethod.id,
            type: 'SubmissionPaymentMethods::Saved',
          };

        request.submission.submissionPaymentMethodAttributes = submissionPaymentMethodAttributes;
        request.submission.paymentIntentId = paymentIntent.id;
      }

      return isEventPage
        ? submitEventPageAsync({ ...request, type: 'event' })
        : submitActionPageAsync(request);
    },
    [processPayment, submitActionPageAsync, submitEventPageAsync, useSubPaymentFlow]
  );

  return {
    error: paymentError || submissionError || eventSubmissionError,
    isLoading: isProcessingPayment || isSubmitting || isSubmittingEvent,
    submit,
  };
};

